proof fn phi_1_leads_to_unfold_intensional_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>, i: nat)
    requires
        p.leads_to(q).satisfied_by(ex),
    ensures
        p.implies(eventually(q)).satisfied_by(ex.suffix(i)),
{
    leads_to_unfold::<int>(ex, p, q);
}

proof fn phi_2_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.satisfied_by(ex),
        (p.pred)(ex) ==> (q.pred)(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_3_or_leads_to_combine_false_spec(p: TempPred<int>, q: TempPred<int>, r: TempPred<int>)
    requires
        TempPred::<int>::new(|ex: Execution<int>| false).entails(p.leads_to(r)),
        TempPred::<int>::new(|ex: Execution<int>| false).entails(q.leads_to(r)),
    ensures
        TempPred::<int>::new(|ex: Execution<int>| false).entails(p.or(q).leads_to(r)),
{
    or_leads_to_combine::<int>(TempPred::new(|ex: Execution<int>| false), p, q, r);
}

proof fn phi_4_or_leads_to_self(spec: TempPred<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        spec.entails(p.leads_to(p.or(q))),
        spec.entails(q.leads_to(p.or(q))),
    ensures
        spec.entails(p.or(q).leads_to(p.or(q))),
{
    or_leads_to_combine::<int>(spec, p, q, p.or(q));
}

proof fn phi_5_leads_to_unfold_at_zero(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.leads_to(q).satisfied_by(ex),
        p.satisfied_by(ex),
    ensures
        eventually(q).satisfied_by(ex),
{
    leads_to_unfold::<int>(ex, p, q);
    implies_apply::<int>(ex, p, eventually(q));
}
